from flask import Flask, render_template_string, request
from markupsafe import escape as prevent_xss

app = Flask(__name__)

@app.route('/', methods=['GET', 'POST'])
def index():
    if request.method == 'POST':
        user_input = request.form['user_input']
        user_input = prevent_xss(user_input)
        return render_template_string('Hello {{ user_input }}!', user_input=user_input)
    return render_template_string('Enter your name: <input type="text" name="user_input">', method='POST')

@app.errorhandler(404)
def page_not_found(e):
    return prevent_xss(str(e))

if __name__ == '__main__':
    app.run(debug=True)
