This code uses the `StringEscapeUtils.escapeHtml4()` function from Apache Commons Text library to escape special characters in the user input, effectively sanitizing it for display.

function sql_escape(s) {
    var escape_chars = {
        "\0": "\\0",
        "\n": "\\n",
        "\r": "\\r",
        "\t": "\\t",
        "\b": "\\b",
        "\f": "\\f",
        "\'": "\\'",
        "\\": "\\\\",
        "\"": "\\\"",
        "\x00": "\\x00"
    };

    var sanitized = "";
    for (var i = 0; i < s.length; i++) {
        var c = s.charAt(i);
        if (escape_chars[c]) {
            sanitized += escape_chars[c];
        } else if (c.charCodeAt(0) < 32 || c.charCodeAt(0) > 126) {
            sanitized += "\\" + c.charCodeAt(0).toString(16).padStart(2, "0");
        } else {
            sanitized += c;
        }
    }

    return sanitized;
}

