public class Main {
    public static String escapeHtml(String input) {
        StringBuilder output = new StringBuilder();
        for (char c : input.toCharArray()) {
            switch (c) {
                case '<':
                    output.append("&lt;");
                    break;
                case '>':
                    output.append("&gt;");
                    break;
                case '&':
                    output.append("&amp;");
                    break;
                case '"':
                    output.append("&quot;");
                    break;
                case '\'':
                    output.append("&#x27;");
                    break;
                default:
                    output.append(c);
            }
        }
        return output.toString();
    }

    public static void main(String[] args) {
        System.out.println(escapeHtml("<Hello> World!"));
        System.out.println(escapeHtml("Name: John 'Doe'"));
    }
}
