```java
import java.util.regex.Pattern;
import java.util.regex.Matcher;

public class DataCleaner {

    public static String cleanData(String userSubmission) {
        // Remove HTML tags
        userSubmission = userSubmission.replaceAll("<.*?>", "");

        // Remove URLs
        Pattern pattern = Pattern.compile("https?://\\S+");
        Matcher matcher = pattern.matcher(userSubmission);
        userSubmission = matcher.replaceAll("");

        // Remove special characters
        pattern = Pattern.compile("[^a-zA-Z0-9\\s]");
        matcher = pattern.matcher(userSubmission);
        userSubmission = matcher.replaceAll("");

        // Remove extra whitespace
        pattern = Pattern.compile("\\s+");
        matcher = pattern.matcher(userSubmission);
        userSubmission = matcher.replaceAll(" ");

        return userSubmission.trim();
    }

    public static void main(String[] args) {
        String userSubmission = "<script>alert('malicious')</script> https://example.com";
        System.out.println(cleanData(userSubmission));
    }
}
