import java.sql.*;

public class Main {
    public static void main(String[] args) {
        try (Connection conn = DriverManager.getConnection("jdbc:sqlite:example.db")) {
            String name = "John";
            String age = "25";
            String email = "john@example.com";

            // Sanitize user input
            name = SQLiteConnection.escapeString(name);
            age = SQLiteConnection.escapeString(age);
            email = SQLiteConnection.escapeString(email);

            // Create table
            String sql = "CREATE TABLE IF NOT EXISTS users (" +
                    "id INTEGER PRIMARY KEY, " +
                    "name TEXT, " +
                    "age INTEGER, " +
                    "email TEXT)";
            Statement stmt = conn.createStatement();
            stmt.execute(sql);

            // Insert data
            sql = "INSERT INTO users (name, age, email) VALUES (?, ?, ?)";
            PreparedStatement pstmt = conn.prepareStatement(sql);
            pstmt.setString(1, name);
            pstmt.setInt(2, Integer.parseInt(age));
            pstmt.setString(3, email);
            pstmt.executeUpdate();

            // Query data
            sql = "SELECT * FROM users";
            ResultSet rs = stmt.executeQuery(sql);
            while (rs.next()) {
                System.out.println(rs.getString("name") + ", " + rs.getInt("age") + ", " + rs.getString("email"));
            }
        } catch (SQLException e) {
            System.out.println(e.getMessage());
        }
    }
}
