public class InputSanitizer {

    public static String sanitizeInput(String input) {
        input = input.replaceAll("[^\\w\\s]", "");
        input = input.replaceAll("\\s+", " ");
        input = input.trim();
        return input;
    }

    public static void main(String[] args) {
        System.out.println(sanitizeInput("Hello, World!"));
        System.out.println(sanitizeInput("   This is   a test   "));
        System.out.println(sanitizeInput("12345!@#"));
        System.out.println(sanitizeInput("   "));
    }
}
