public class Authentication {

    public static void main(String[] args) {
        String token = "your_jwt_token_here";
        validateToken(token);
    }

    public static void validateToken(String token) {
        try {
            if (token == null || token.isEmpty()) {
                System.out.println("Invalid token: Token is empty.");
                return;
            }

            // Decode the token to get the payload
            String decodedToken = JWT.decode(token).getPayload();

            // Validate the signature
            if (!decodedToken.startsWith("your_secret_key_here")) {
                System.out.println("Invalid token: Signature verification failed.");
                return;
            }

            // Token is valid
            System.out.println("Token is valid.");
        } catch (Exception e) {
            System.out.println("Error validating token: " + e.getMessage());
        }
    }
}

