import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class InputSanitizer {

    private static final String[] UNSAFE_CHARACTERS = {"<", ">", "(", ")", "&", "%", "$", "#", "@", "\"", "\'", "\\\\", "\\^", "\\*", "\\+=", "\\-"};

    public static String sanitizeInput(String input) {
        input = input.replaceAll("<", "&lt;");
        input = input.replaceAll(">", "&gt;");
        input = input.replaceAll("\\*", "");
        input = input.replaceAll("\\+", "");
        input = input.replaceAll("\\(", "");
        input = input.replaceAll("\\)", "");
        input = input.replaceAll("&", "&amp;");
        input = input.replaceAll("%", "");
        input = input.replaceAll("$", "");
        input = input.replaceAll("#", "");
        input = input.replaceAll("@", "");
        input = input.replaceAll("\"", "");
        input = input.replaceAll("'", "");
        input = input.replaceAll("\\\\", "");
        input = input.replaceAll("\\^", "");
        input = input.replaceAll("\\[", "");
        input = input.replaceAll("\\]", "");
        input = input.replaceAll("\\{", "");
        input = input.replaceAll("\\}", "");
        input = input.replaceAll("\\|", "");

        for (String character : UNSAFE_CHARACTERS) {
            input = input.replaceAll(Pattern.quote(character), "");
        }

        return input;
    }

    public static void main(String[] args) {
        System.out.println(sanitizeInput("<script>alert('XSS')</script>"));
        System.out.println(sanitizeInput("%2Fvar%2Flog.txt"));
        System.out.println(sanitizeInput("$"));
    }
}
