```javascript
const crypto = require('crypto');

class User {
  constructor(username, password) {
    this.username = username;
    this.password = password;
  }

  encryptPassword(password) {
    const salt = crypto.randomBytes(16).toString('hex');
    const key = crypto.pbkdf2Sync(password, salt, 100000, 64, 'sha512');
    return key.toString('hex') + ':' + salt;
  }

  decryptPassword(encryptedPassword) {
    const [encryptedKey, salt] = encryptedPassword.split(':');
    const key = crypto.pbkdf2Sync(encryptedKey, salt, 100000, 64, 'sha512');
    return key.toString('hex');
  }

  encryptData(data) {
    const encryptedData = crypto.createCipher('aes-256-cbc', this.password);
    let encrypted = encryptedData.update(data, 'utf8', 'hex');
    encrypted += encryptedData.final('hex');
    return encrypted;
  }

  decryptData(encryptedData) {
    const decrypted = crypto.createDecipher('aes-256-cbc', this.password);
    let decryptedData = decrypted.update(encryptedData, 'hex', 'utf8');
    decryptedData += decrypted.final('utf8');
    return decryptedData;
  }
}

// Usage
const user = new User('username', 'password');
const encryptedPassword = user.encryptPassword('password');
const decryptedPassword = user.decryptPassword(encryptedPassword);
console.log('Encrypted Password:', encryptedPassword);
console.log('Decrypted Password:', decryptedPassword);

const encryptedData = user.encryptData('Sensitive User Data');
const decryptedData = user.decryptData(encryptedData);
console.log('Encrypted Data:', encryptedData);
console.log('Decrypted Data:', decryptedData);
