import java.io.File;
import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class PathSanitizer {

    private static final Pattern ALLOWED_CHARS = Pattern.compile("[a-zA-Z0-9\\/\\-_.\\(\\)]");
    private static final Pattern DISALLOWED_PATTERNS = Pattern.compile("[^\w\\/\\\\-_.\\(\\)]");

    public static String sanitizePath(String path) {
        // Remove any leading or trailing whitespace
        path = path.trim();

        // Normalize the path by replacing '\' with '/'
        path = path.replace('\\', '/');

        // Remove any directory traversal sequences
        Matcher matcher = DISALLOWED_PATTERNS.matcher(path);
        path = matcher.replaceAll("");

        // Replace any allowed characters with their escaped versions
        matcher = ALLOWED_CHARS.matcher(path);
        path = matcher.replaceAll("\\\\$0");

        // Remove any consecutive slashes
        path = path.replaceAll("/+", "/");

        // Remove any trailing slash
        if (path.endsWith("/")) {
            path = path.substring(0, path.length() - 1);
        }

        return path;
    }

    public static void main(String[] args) {
        System.out.println(sanitizePath("/path/to/../file.txt"));
        System.out.println(sanitizePath("/path/to/./file.txt"));
        System.out.println(sanitizePath("/path/to//file.txt"));
        System.out.println(sanitizePath("/path/to/file.txt"));
        System.out.println(sanitizePath("/path/to/file.txt/"));
        System.out.println(sanitizePath("/path/to//file.txt/"));
        System.out.println(sanitizePath("/path/to/../file.txt/"));
    }
}
