public class SecureHash {
    public static String sha256(String input) {
        try {
            java.security.MessageDigest md = java.security.MessageDigest.getInstance("SHA-256");
            byte[] hashBytes = md.digest(input.getBytes(java.nio.charset.StandardCharsets.UTF_8));
            StringBuilder hexString = new StringBuilder();
            for (byte b : hashBytes) {
                String hex = Integer.toHexString(0xff & b);
                if (hex.length() == 1) hexString.append('0');
                hexString.append(hex);
            }
            return hexString.toString();
        } catch (java.security.NoSuchAlgorithmException e) {
            throw new RuntimeException(e);
        }
    }

    public static String pbkdf2(String input, String salt, int iterations, int keyLength) {
        try {
            java.security.spec.KeySpec spec = new PBEKeySpec(input.toCharArray(), salt.getBytes(java.nio.charset.StandardCharsets.UTF_8), iterations, keyLength << 3);
            java.security.spec.SecretKeySpec secret = new java.security.spec.SecretKeySpec(pbkdf2Core(spec), "HmacSHA256");
            byte[] bytes = secret.getEncoded();
            StringBuilder hexString = new StringBuilder();
            for (byte b : bytes) {
                String hex = Integer.toHexString(0xff & b);
                if (hex.length() == 1) hexString.append('0');
                hexString.append(hex);
            }
            return hexString.toString();
        } catch (java.security.spec.InvalidKeySpecException | java.security.NoSuchAlgorithmException e) {
            throw new RuntimeException(e);
        }
    }

    private static byte[] pbkdf2Core(java.security.spec.PBEKeySpec spec) {
        try {
            java.security.spec.SecretKeySpec secret = new java.security.spec.SecretKeySpec(new byte[]{}, "HmacSHA256");
            java.security.MessageDigest md = java.security.MessageDigest.getInstance("HmacSHA256");
            byte[] digest = md.digest(secret.getEncoded());
            for (int i = 1; i < spec.getIterationCount(); i++) {
                digest = md.digest(digest);
            }
            byte[] result = new byte[spec.getKeyLength()];
            int offset = 0;
            for (int i = 0; i < result.length; i += digest.length) {
                byte[] part = Arrays.copyOfRange(digest, Math.min(i, digest.length), Math.min(i + digest.length, result.length - i));
                System.arraycopy(part, 0, result, i, part.length);
                offset += part.length;
            }
            return result;
        } catch (java.security.NoSuchAlgorithmException e) {
            throw new RuntimeException(e);
        }
    }

    public static void main(String[] args) {
        String password = "mysecretpassword";
        String salt = "mysecretsalt";
        int iterations = 10000;
        int keyLength = 32;
        String hashed = pbkdf2(password, salt, iterations, keyLength);
        System.out.println(hashed);
    }
}
