@RestController
public class ApiEndpoint {

    @Autowired
    private RequestSanitizer sanitizer;

    @PostMapping("/api/endpoint")
    public ResponseEntity<Map<String, Object>> handleRequest(
            @RequestHeader(value = "Authorization") String token,
            @RequestBody Map<String, Object> data,
            HttpServletRequest request
    ) {
        try {
            // Validate token
            Claims claims = Jwts.parser().setSigningKey("secretKey").parseClaimsJws(token).getBody();
            String userId = claims.getSubject();

            // Sanitize incoming request
            Map<String, Object> sanitizedData = sanitizer.sanitizeRequest(data);

            // Process sanitized data
            Map<String, Object> response = processSanitizedData(sanitizedData, userId);

            return ResponseEntity.ok(response);
        } catch (JwtException e) {
            return ResponseEntity.status(HttpStatus.FORBIDDEN).body(Map.of("error", "Invalid token"));
        } catch (Exception e) {
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body(Map.of("error", "Internal server error"));
        }
    }

    private Map<String, Object> processSanitizedData(Map<String, Object> sanitizedData, String userId) {
        // Implement your business logic here
        return Map.of("message", "Data processed successfully");
    }
}

class RequestSanitizer {

    public Map<String, Object> sanitizeRequest(Map<String, Object> data) {
        // Implement your sanitization logic here
        return Map.of("key", data.get("key"));
    }
}
