```python
import re

class ShellCommandSanitizer:
    def __init__(self):
        self.special_chars = [";", "&", "|", "$(", "$)", "\\", ">", "<"]

    def sanitize(self, command):
        command = re.sub(r"(\s+)", r" \1 ", command)
        command = re.sub(r"([^\w\s]+)", r"\\\1", command)
        for char in self.special_chars:
            command = re.sub(re.escape(char), r"\\" + re.escape(char), command)
        return command.rstrip()

    def escape(self, command):
        return re.sub(r"([^\w\s])", r"\\\1", command)

    def unescape(self, command):
        return re.sub(r"\\(.)", r"\1", command)

def shell_command_sanitizer(command):
    sanitizer = ShellCommandSanitizer()
    sanitized_command = sanitizer.sanitize(command)
    return sanitized_command

def main():
    command = input("Enter a shell command: ")
    print(shell_command_sanitizer(command))

if __name__ == "__main__":
    main()
```

This code provides a simple shell command sanitizer that replaces special characters with their escaped versions. It also includes a method to escape special characters and unescape them. The `shell_command_sanitizer` function is used to sanitize a command. The `main` function is used to test the sanitizer.

