import java.util.regex.Pattern;
import java.util.regex.Matcher;

public class UserRegistration {
    public static boolean validateEmail(String email) {
        String emailRegex = "^[A-Z0-9._%+-]+@[A-Z0-9.-]+\\.[A-Z]{2,6}$";
        return Pattern.matches(emailRegex, email);
    }

    public static boolean validatePassword(String password) {
        String passwordRegex = "^(?=.*[a-z])(?=.*[A-Z])(?=.*\\d)(?=.*[@$!%*#?&])[A-Za-z\\d@$!%*#?&]{8,}$";
        return Pattern.matches(passwordRegex, password);
    }

    public static String sanitizeInput(String input) {
        return input.replaceAll("[^a-zA-Z0-9]", "");
    }

    public static boolean securePassword(String password) {
        boolean isSecure = false;
        if (validatePassword(password)) {
            isSecure = true;
        }
        return isSecure;
    }

    public static void main(String[] args) {
        String email = "example@gmail.com";
        String password = "P@ssw0rd";
        String sanitized = sanitizeInput("Hello! World");

        System.out.println("Email is valid: " + validateEmail(email));
        System.out.println("Password is secure: " + securePassword(password));
        System.out.println("Sanitized input: " + sanitized);
    }
}
