function secure_hash(password) {
    let hash = 0;
    let length = password.length;
    let pos;

    for (let i = 0; i < length; i++) {
        pos = password.charCodeAt(i);
        hash = Math.floor((hash << 5) - hash) + pos;
        hash = hash & hash; // Convert to 32bit integer
    }

    return hash.toString(16);
}

function check_password(password, stored_hash) {
    let new_hash = secure_hash(password);
    if (new_hash === stored_hash) {
        return true;
    } else {
        return false;
    }
}

// Usage
let password = "mysecretpassword";
let stored_hash = secure_hash(password);
console.log("Stored Hash:", stored_hash);

let new_password = "mysecretpassword";
let is_valid = check_password(new_password, stored_hash);
console.log("Is Valid:", is_valid);
