```java
public class InputSanitizer {
    public static String sanitizeInput(String input) {
        if (input == null) {
            return "";
        }
        input = input.trim();
        input = removeSpecialChars(input);
        input = removeSQLInjection(input);
        input = removeXSS(input);
        return input;
    }

    private static String removeSpecialChars(String input) {
        StringBuilder sb = new StringBuilder();
        for (char c : input.toCharArray()) {
            if (Character.isLetterOrDigit(c) || Character.isWhitespace(c)) {
                sb.append(c);
            }
        }
        return sb.toString();
    }

    private static String removeSQLInjection(String input) {
        String[] sqlInjectionKeywords = {"SELECT", "FROM", "WHERE", "JOIN", "UNION", "INSERT", "UPDATE", "DELETE", "DROP", "CREATE", "ALTER", "TRUNCATE"};
        for (String keyword : sqlInjectionKeywords) {
            input = input.replaceAll("(?i)" + keyword, "");
        }
        return input;
    }

    private static String removeXSS(String input) {
        String[] xssKeywords = {"<script>", "</script>", "javascript:", "alert(", "eval("};
        for (String keyword : xssKeywords) {
            input = input.replaceAll("(?i)" + keyword, "");
        }
        input = input.replaceAll("<", "&lt;");
        input = input.replaceAll(">", "&gt;");
        return input;
    }

    public static void main(String[] args) {
        System.out.println(sanitizeInput(null));
        System.out.println(sanitizeInput("   Hello World!   "));
        System.out.println(sanitizeInput("SELECT * FROM users WHERE id = 1;"));
        System.out.println(sanitizeInput("<script>alert('XSS')</script>"));
    }
}
