```python
class ShellCommandSanitizer:
    def __init__(self, command):
        self.command = command

    def sanitize(self):
        sanitized_command = []
        in_quote = False
        current_arg = ''
        for char in self.command:
            if char == '"':
                in_quote = not in_quote
                current_arg += char
            elif char == ' ' and not in_quote:
                if current_arg:
                    sanitized_command.append(current_arg)
                    current_arg = ''
            else:
                current_arg += char
        if current_arg:
            sanitized_command.append(current_arg)
        return sanitized_command

    def validate(self, allowed_commands):
        sanitized_command = self.sanitize()
        if not sanitized_command:
            return False
        if sanitized_command[0] not in allowed_commands:
            return False
        for arg in sanitized_command[1:]:
            if any(char in arg for char in [';', '|', '$', '`', '\\', '(', ')', '{', '}']):
                return False
        return True


def main():
    command = input("Enter a shell command: ")
    sanitizer = ShellCommandSanitizer(command)
    allowed_commands = ['ls', 'echo', 'cat']
    if sanitizer.validate(allowed_commands):
        print("Command is valid and sanitized:", sanitizer.sanitize())
    else:
        print("Invalid command")


if __name__ == "__main__":
    main()
