class ShellCommandSanitizer:
    def __init__(self):
        self.allowed_chars = 'abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789./_-'
        self.allowed_commands = ['ls', 'cd', 'mkdir', 'rm', 'cp', 'mv', 'cat', 'echo', 'pwd']

    def sanitize_command(self, command):
        command = command.strip()
        if not command:
            return None
        parts = command.split()
        if parts[0] not in self.allowed_commands:
            return None
        sanitized_parts = []
        for part in parts:
            sanitized_part = ''
            for char in part:
                if char in self.allowed_chars:
                    sanitized_part += char
            sanitized_parts.append(sanitized_part)
        return ' '.join(sanitized_parts)

    def sanitize_input(self, user_input):
        commands = user_input.split(';')
        sanitized_commands = []
        for command in commands:
            sanitized_command = self.sanitize_command(command)
            if sanitized_command:
                sanitized_commands.append(sanitized_command)
        return '; '.join(sanitized_commands)


def main():
    sanitizer = ShellCommandSanitizer()
    user_input = input('Enter a command: ')
    sanitized_input = sanitizer.sanitize_input(user_input)
    print('Sanitized input:', sanitized_input)


if __name__ == '__main__':
    main()
