function sanitizeSql(input) {
    return input.replace(/[^a-zA-Z0-9\s]/g, '');
}

function escapeHtml(unsafe) {
    return unsafe
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;')
        .replace(/'/g, '&#039;');
}

function validateInput(input) {
    return typeof input === 'string' && input.trim() !== '';
}
