```javascript
function sanitizePath(path) {
  const normalizedPath = path.replace(/\/+/g, '/').replace(/\/\./g, '');
  const pathParts = normalizedPath.split('/');
  const sanitizedPathParts = [];

  for (const part of pathParts) {
    if (part === '..') {
      if (sanitizedPathParts.length > 0) {
        sanitizedPathParts.pop();
      }
    } else if (part !== '' && part !== '.') {
      sanitizedPathParts.push(part);
    }
  }

  return '/' + sanitizedPathParts.join('/');
}

function isWithinDirectory(sanitizedPath, baseDirectory) {
  const baseParts = baseDirectory.split('/');
  const pathParts = sanitizedPath.split('/');

  for (let i = 0; i < baseParts.length; i++) {
    if (pathParts[i] !== baseParts[i]) {
      return false;
    }
  }

  return true;
}

function secureJoin(baseDirectory, path) {
  const sanitizedPath = sanitizePath(path);
  if (!isWithinDirectory(sanitizedPath, baseDirectory)) {
    throw new Error('Path is outside the base directory');
  }
  return sanitizedPath;
}
