                continue;
            }
            // Inside single quotes, backslash is literal
            current += ch;
            continue;
        }

        if (ch === "'" && !inDouble) {
            inSingle = !inSingle;
            continue;
        }

        if (ch === '"' && !inSingle) {
            inDouble = !inDouble;
            continue;
        }

        if (/\s/.test(ch) && !inSingle && !inDouble) {
            if (current.length > 0) {
                tokens.push(current);
                current = '';
            }
            continue;
        }

        current += ch;
    }
    if (current.length > 0) tokens.push(current);

    // Escape each token safely
    const safeTokens = tokens.map(token => {
        // If token already safe (only allowed chars), return as‑is
        if (/^[a-zA-Z0-9._\/-]+$/.test(token)) {
            return token;
        }
        // Otherwise, wrap in single quotes and escape inner single quotes
        const escaped = token.replace(/'/g, `'\\''`);
        return `'${escaped}'`;
    });

    return safeTokens.join(' ');
