import java.nio.file.LinkOption;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.nio.file.Files;

public final class PathSanitizer {
    private final Path baseDirectory;

    public PathSanitizer(String baseDir) throws IOException {
        if (baseDir == null) {
            throw new IllegalArgumentException("Base directory cannot be null");
        }
        Path base = Paths.get(baseDir).toAbsolutePath().normalize();
        if (!Files.isDirectory(base)) {
            throw new IllegalArgumentException("Base directory does not exist or is not a directory: " + base);
        }
        this.baseDirectory = base;
    }

    /**
     * Sanitizes a user-supplied path, ensuring it resolves within the configured base directory.
     *
     * @param userPath the path supplied by the user (may be relative or absolute)
     * @return a normalized, absolute Path that is guaranteed to be inside the base directory
     * @throws IOException if an I/O error occurs while resolving the path
     * @throws SecurityException if the resolved path attempts to escape the base directory
     */
    public Path sanitize(String userPath) throws IOException, SecurityException {
        if (userPath == null) {
            throw new IllegalArgumentException("User path cannot be null");
        }

        // Resolve the user path against the base directory without allowing it to be absolute
        Path resolved = baseDirectory.resolve(userPath).normalize();

        // Resolve symbolic links without following them to avoid unexpected traversal
        Path realPath = resolved.toRealPath(LinkOption.NOFOLLOW_LINKS);

        // Ensure the final path starts with the base directory
        if (!realPath.startsWith(baseDirectory)) {
            throw new SecurityException("Attempted directory traversal detected: " + userPath);
        }

        return realPath;
    }

    // Simple demonstration
    public static void main(String[] args) {
        try {
            // Define a safe root directory (adjust as needed)
            String safeRoot = System.getProperty("user.dir") + "/safe_root";

            // Ensure the directory exists
            Files.createDirectories(Paths.get(safeRoot));

            PathSanitizer sanitizer = new PathSanitizer(safeRoot);

            // Example user inputs
            String[] inputs = {
                "documents/report.txt",
                "../outside.txt",
                "/absolute/path/evil.txt",
                "subdir/../subdir2/file.txt",
                "symlinked/../secret.txt"
            };

            for (String input : inputs) {
                try {
                    Path safePath = sanitizer.sanitize(input);
                    System.out.println("Original: " + input + " => Sanitized: " + safePath);
                } catch (SecurityException se) {
                    System.out.println("Original: " + input + " => BLOCKED (" + se.getMessage() + ")");
                }
            }
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

