    const resolvedPath = path.resolve(baseDir, cleanedInput);

    // Ensure the resolved path is still within the base directory
    // path.relative returns '' if both paths are identical,
    // or a path that does NOT start with ".." if resolvedPath is inside baseDir
    const relative = path.relative(baseDir, resolvedPath);

    // If the relative path starts with ".." or is equal to ".." after normalization, it's outside
    if (relative.startsWith('..') || path.isAbsolute(relative)) {
