public class Main {
    public static String escapeShell(String str) {
        if (str == null || str.isEmpty()) {
            return "''";
        }

        StringBuilder sb = new StringBuilder("'");

        for (int i = 0; i < str.length(); i++) {
            char c = str.charAt(i);
            if (c == '\'') {
                sb.append("'\\''");
            } else {
                sb.append(c);
            }
        }

        sb.append("'");
        return sb.toString();
    }

    public static void main(String[] args) {
        System.out.println(escapeShell("Hello, World!"));
        System.out.println(escapeShell("It's a test"));
    }
}
