def sanitize_shell_command(command):
    sanitized_command = []
    in_quote = False
    current_arg = ""

    for char in command:
        if char == '"':
            if in_quote:
                sanitized_command.append(current_arg.replace('\\"', '"'))
                current_arg = ""
                in_quote = False
            else:
                in_quote = True
        elif char == "'":
            if in_quote:
                if current_arg:
                    sanitized_command.append(current_arg.replace("\\'", "'"))
                    current_arg = ""
                in_quote = False
            else:
                in_quote = True
        elif char.isspace() and not in_quote:
            if current_arg:
                sanitized_command.append(current_arg)
                current_arg = ""
        elif char == '\\' and in_quote:
            current_arg += char
        else:
            current_arg += char

    if current_arg:
        sanitized_command.append(current_arg)

    return sanitized_command


def main():
    command = input("Enter a shell command: ")
    sanitized = sanitize_shell_command(command)
    print("Sanitized command:", sanitized)


if __name__ == "__main__":
    main()
