```python
import os
import secrets

def generate_salt(size=32):
    return secrets.token_bytes(size)

def xor_bytes(a, b):
    return bytes(x ^ y for x, y in zip(a, b))

def hash_password(password, salt=None):
    if salt is None:
        salt = generate_salt()
    password_bytes = password.encode('utf-8')
    salted_password = password_bytes + salt
    hash_value = salted_password
    for _ in range(100000):
        hash_value = xor_bytes(hash_value, salted_password)
        hash_value = bytes([x ^ (x >> 4) for x in hash_value])
    return salt.hex() + hash_value.hex()

def verify_password(stored_hash, provided_password):
    salt = bytes.fromhex(stored_hash[:64])
    stored_hash_value = bytes.fromhex(stored_hash[64:])
    password_bytes = provided_password.encode('utf-8')
    salted_password = password_bytes + salt
    hash_value = salted_password
    for _ in range(100000):
        hash_value = xor_bytes(hash_value, salted_password)
        hash_value = bytes([x ^ (x >> 4) for x in hash_value])
    return hash_value == stored_hash_value

def main():
    password = "mysecretpassword"
    stored_hash = hash_password(password)
    print("Stored Hash:", stored_hash)
    is_valid = verify_password(stored_hash, password)
    print("Is password valid?", is_valid)

if __name__ == "__main__":
    main()
