import subprocess

def sanitize_command(command):
    # This is a very basic example. In real-world scenarios, you should use a whitelist approach.
    allowed_commands = ['ls', 'echo', 'pwd']
    command_parts = command.split()
    if command_parts[0] not in allowed_commands:
        raise ValueError("Invalid command")

    return command

def execute_command(command):
    try:
        sanitized_command = sanitize_command(command)
        output = subprocess.check_output(sanitized_command, shell=True)
        return output.decode('utf-8').strip()
    except subprocess.CalledProcessError as e:
        return f"Command failed with return code {e.returncode}"
    except Exception as e:
        return f"An error occurred: {str(e)}"

# Example usage
