```javascript
function sanitizePath(inputPath, baseDirectory) {
  const path = require('path');

  // Normalize the input path
  const normalizedPath = path.normalize(inputPath);

  // Remove any null bytes
  const sanitizedPath = normalizedPath.replace(/\0/g, '');

  // Join the base directory and the sanitized path
  const joinedPath = path.join(baseDirectory, sanitizedPath);

  // Resolve the joined path to remove any relative paths
  const resolvedPath = path.resolve(joinedPath);

  // Check if the resolved path is within the base directory
  if (!resolvedPath.startsWith(baseDirectory)) {
    throw new Error('Directory traversal attack detected');
  }

  // Return the sanitized path relative to the base directory
  return path.relative(baseDirectory, resolvedPath);
}

// Example usage
const baseDir = '/var/www/html';
const userInput = '../../etc/passwd';
try {
  const sanitized = sanitizePath(userInput, baseDir);
  console.log(sanitized);
} catch (e) {
  console.log(e.message);
}
