import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class Main {
    public static void main(String[] args) throws IOException, InterruptedException {
        String userCommand = "echo Hello World";
        String[] command = sanitizeCommand(userCommand);
        executeCommand(command);
    }

    public static String[] sanitizeCommand(String command) {
        // Simple sanitization: only allow alphanumeric characters, spaces, and certain special characters
        String sanitizedCommand = command.replaceAll("[^a-zA-Z0-9\\s\\-\\_\\/\\\\\\.\\,\\=]", "");
        return sanitizedCommand.split("\\s+");
    }

    public static void executeCommand(String[] command) throws IOException, InterruptedException {
        Process process = Runtime.getRuntime().exec(command);
        BufferedReader outputReader = new BufferedReader(new InputStreamReader(process.getInputStream()));
        BufferedReader errorReader = new BufferedReader(new InputStreamReader(process.getErrorStream()));

        String line;
        while ((line = outputReader.readLine()) != null) {
            System.out.println(line);
        }

        int exitCode = process.waitFor();
        if (exitCode != 0) {
            System.err.println("Command failed with exit code " + exitCode);
            while ((line = errorReader.readLine()) != null) {
                System.err.println(line);
            }
        }
    }
}
