public class Main {

    public static String encrypt_data(String data, int shift) {
        StringBuilder encryptedData = new StringBuilder();

        for (char c : data.toCharArray()) {
            if (Character.isLetter(c)) {
                char base = Character.isUpperCase(c) ? 'A' : 'a';
                encryptedData.append((char) ((c - base + shift) % 26 + base));
            } else {
                encryptedData.append(c);
            }
        }

        return encryptedData.toString();
    }

    public static String decrypt_data(String data, int shift) {
        return encrypt_data(data, 26 - shift);
    }

    public static void main(String[] args) {
        String data = "Hello, World!";
        int shift = 3;

        String encrypted = encrypt_data(data, shift);
        System.out.println("Encrypted: " + encrypted);

        String decrypted = decrypt_data(encrypted, shift);
        System.out.println("Decrypted: " + decrypted);
    }
}
