```java
import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class HtmlSanitizer {
    private static final String[] ALLOWED_TAGS = {"p", "img", "br", "strong", "em", "u", "s", "a", "ul", "ol", "li"};
    private static final String[] ALLOWED_ATTRIBUTES = {"src", "href", "alt"};

    public static String sanitize(String html) {
        // Remove script and style tags
        html = html.replaceAll("<(script|style).*?>.*?<\\/\\1>", "");

        // Remove comments
        html = html.replaceAll("<!--.*?-->", "");

        // Remove disallowed tags
        for (String tag : getDisallowedTags(html)) {
            html = html.replaceAll("<" + tag + ".*?>.*?<\\/\\s*" + tag + ">", "");
            html = html.replaceAll("<" + tag + ".*?>", "");
        }

        // Remove disallowed attributes
        html = removeDisallowedAttributes(html);

        // Escape special characters
        html = html.replaceAll("&", "&amp;");
        html = html.replaceAll("<", "&lt;");
        html = html.replaceAll(">", "&gt;");

        return html;
    }

    private static String[] getDisallowedTags(String html) {
        Pattern pattern = Pattern.compile("<(\\w+).*?>.*?<\\/\\s*\\1>");
        Matcher matcher = pattern.matcher(html);
        StringBuilder disallowedTags = new StringBuilder();
        while (matcher.find()) {
            String tag = matcher.group(1);
            boolean allowed = false;
            for (String allowedTag : ALLOWED_TAGS) {
                if (tag.equals(allowedTag)) {
                    allowed = true;
                    break;
                }
            }
            if (!allowed) {
                disallowedTags.append(tag).append(",");
            }
        }
        if (disallowedTags.length() > 0) {
            return disallowedTags.toString().split(",");
        } else {
            return new String[0];
        }
    }

    private static String removeDisallowedAttributes(String html) {
        Pattern pattern = Pattern.compile("\\b(\\w+)\\s*=\\s*\"[^\"]*\"");
        Matcher matcher = pattern.matcher(html);
        StringBuffer stringBuffer = new StringBuffer();
        while (matcher.find()) {
            String attribute = matcher.group(1);
            boolean allowed = false;
            for (String allowedAttribute : ALLOWED_ATTRIBUTES) {
                if (attribute.equals(allowedAttribute)) {
                    allowed = true;
                    break;
                }
            }
            if (!allowed) {
                matcher.appendReplacement(stringBuffer, "");
            } else {
                matcher.appendReplacement(stringBuffer, matcher.group(0));
            }
        }
        matcher.appendTail(stringBuffer);
        return stringBuffer.toString();
    }

    public static void main(String[] args) {
        String html = "<p>Hello <script>alert('XSS')</script> world!</p><img src='image.jpg' onerror='alert(\"XSS\")'>";
        System.out.println(sanitize(html));
    }
}
