```python
import re

class Sanitizer:
    def __init__(self, allowed_chars=None, allowed_commands=None):
        if allowed_chars is None:
            allowed_chars = set('abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789._/-')
        if allowed_commands is None:
            allowed_commands = set(['ls', 'cd', 'mkdir', 'rm', 'cp', 'mv', 'find', 'grep', 'echo'])
        self.allowed_chars = allowed_chars
        self.allowed_commands = allowed_commands

    def sanitize(self, command):
        command = command.strip()
        if not command:
            return None
        parts = self.split_command(command)
        if not parts:
            return None
        if parts[0] not in self.allowed_commands:
            return None
        sanitized_parts = []
        for part in parts:
            sanitized_part = self.sanitize_part(part)
            if not sanitized_part:
                return None
            sanitized_parts.append(sanitized_part)
        return ' '.join(sanitized_parts)

    def split_command(self, command):
        parts = []
        current_part = ''
        quote = None
        for char in command:
            if quote:
                if char == quote:
                    quote = None
                else:
                    current_part += char
            elif char in [' ', '\t']:
                if current_part:
                    parts.append(current_part)
                    current_part = ''
            elif char in ['"', "'"]:
                quote = char
                current_part += char
            else:
                current_part += char
        if current_part:
            parts.append(current_part)
        return parts

    def sanitize_part(self, part):
        sanitized_part = ''
        for char in part:
            if char in self.allowed_chars:
                sanitized_part += char
            else:
                return None
        return sanitized_part


def main():
    sanitizer = Sanitizer()
    commands = [
        'ls -l',
        'cd ~',
        'mkdir test',
        'rm -rf test',
        'cp test /etc/passwd',
        'mv test /etc/passwd',
        'find . -name test',
        'grep test *',
        'echo test',
        'test; ls',
        'test|ls',
        'test&ls',
    ]
    for command in commands:
        sanitized_command = sanitizer.sanitize(command)
        print(f'Command: {command}, Sanitized: {sanitized_command}')


if __name__ == '__main__':
    main()
