```java
public class Sanitizer {

    public static String sanitize(String input) {
        if (input == null) {
            return "";
        }

        input = trim(input);
        input = removeSpecialChars(input);
        input = removeSQLInjection(input);
        input = removeXSS(input);
        return input;
    }

    private static String trim(String input) {
        return input.replaceAll("^\\s+|\\s+$", "");
    }

    private static String removeSpecialChars(String input) {
        return input.replaceAll("[^a-zA-Z0-9\\s.,!?-]", "");
    }

    private static String removeSQLInjection(String input) {
        input = input.replaceAll("(?i)OR\\s+1\\s*=\\s*1", "");
        input = input.replaceAll("(?i)AND\\s+1\\s*=\\s*1", "");
        input = input.replaceAll("(?i)UNION\\s+SELECT", "");
        input = input.replaceAll("(?i)INSERT\\s+INTO", "");
        input = input.replaceAll("(?i)UPDATE\\s+.*\\s+SET", "");
        input = input.replaceAll("(?i)DELETE\\s+FROM", "");
        input = input.replaceAll("\\s+;\\s*", "");
        return input;
    }

    private static String removeXSS(String input) {
        input = input.replaceAll("<script>.*</script>", "");
        input = input.replaceAll("<.*?>", "");
        input = input.replaceAll("%3C.*%3E", "");
        return input;
    }

    public static void main(String[] args) {
        System.out.println(sanitize(null));
        System.out.println(sanitize("   Hello World!   "));
        System.out.println(sanitize("Hello; World!"));
        System.out.println(sanitize("Hello <script>alert('XSS')</script> World!"));
        System.out.println(sanitize("Hello OR 1=1 World!"));
    }
}
