import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.security.SecureRandom;
import java.util.regex.Pattern;

public class UserRegistration {

    private static final String EMAIL_REGEX = "^[A-Za-z0-9+_.-]+@[A-Za-z0-9.-]+\\.[A-Za-z]{2,}$";

    public static class User {
        private String username;
        private String email;
        private String passwordHash;
        private byte[] salt;

        public User(String username, String email, String passwordHash, byte[] salt) {
            this.username = username;
            this.email = email;
            this.passwordHash = passwordHash;
            this.salt = salt;
        }

        public String getUsername() { return username; }
        public String getEmail() { return email; }
        public String getPasswordHash() { return passwordHash; }
        public byte[] getSalt() { return salt; }
    }

    public static User registerUser(String username, String email, String password) throws Exception {
        if (username == null || email == null || password == null) {
            throw new IllegalArgumentException("All fields are required");
        }

        String sanitizedUsername = sanitize_input(username);
        if (!validate_email(email)) {
            throw new IllegalArgumentException("Invalid email format");
        }
        String[] secured = secure_password(password);
        String passwordHash = secured[0];
        byte[] salt = hexStringToByteArray(secured[1]);

        return new User(sanitizedUsername, email, passwordHash, salt);
    }

    public static String sanitize_input(String input) {
        if (input == null) return null;
        return input.trim().replaceAll("[^A-Za-z0-9 ]", "");
    }

    public static boolean validate_email(String email) {
        if (email == null) return false;
        return Pattern.matches(EMAIL_REGEX, email);
    }

    public static String[] secure_password(String password) throws NoSuchAlgorithmException {
        SecureRandom sr = new SecureRandom();
        byte[] salt = new byte[16];
        sr.nextBytes(salt);
        String saltHex = byteArrayToHexString(salt);
        String hash = hashPassword(password, salt);
        return new String[]{hash, saltHex};
    }

    private static String hashPassword(String password, byte[] salt) throws NoSuchAlgorithmException {
        MessageDigest md = MessageDigest.getInstance("SHA-256");
        md.update(salt);
        byte[] hashedPassword = md.digest(password.getBytes());
        return byteArrayToHexString(hashedPassword);
    }

    private static String byteArrayToHexString(byte[] bytes) {
        StringBuilder sb = new StringBuilder();
        for (byte b : bytes) {
            sb.append(String.format("%02x", b));
        }
        return sb.toString();
    }

    private static byte[] hexStringToByteArray(String hex) {
        int len = hex.length();
        byte[] data = new byte[len / 2];
        for (int i = 0; i < len; i += 2) {
            data[i / 2] = (byte) ((Character.digit(hex.charAt(i), 16) << 4)
                    + Character.digit(hex.charAt(i + 1), 16));
        }
        return data;
    }
}
