public class SecureHash {
    private static final int SALT_LENGTH = 16;
    private static final int HASH_LENGTH = 32;
    private static final int PBKDF2_ITERATIONS = 100000;

    public static byte[] secure_hash(char[] password, byte[] salt) {
        if (salt == null) {
            salt = new byte[SALT_LENGTH];
            for (int i = 0; i < SALT_LENGTH; i++) {
                salt[i] = (byte)(Math.random() * 256);
            }
        }

        byte[] passwordBytes = new byte[password.length * 2];
        for (int i = 0; i < password.length; i++) {
            char c = password[i];
            passwordBytes[i * 2] = (byte)((c >> 8) & 0xff);
            passwordBytes[i * 2 + 1] = (byte)(c & 0xff);
        }

        byte[] hash = new byte[salt.length + passwordBytes.length];
        System.arraycopy(salt, 0, hash, 0, salt.length);
        System.arraycopy(passwordBytes, 0, hash, salt.length, passwordBytes.length);

        for (int i = 0; i < PBKDF2_ITERATIONS; i++) {
            hash = sha256(hash);
        }

        byte[] result = new byte[salt.length + hash.length];
        System.arraycopy(salt, 0, result, 0, salt.length);
        System.arraycopy(hash, 0, result, salt.length, hash.length);

        for (int i = 0; i < passwordBytes.length; i++) {
            passwordBytes[i] = 0;
        }

        return result;
    }

    private static byte[] sha256(byte[] input) {
        int[] h = {0x6a09e667, 0xbb67ae85, 0x3c6ef372, 0xa54ff53a, 0x510e527f, 0x9b05688c, 0x1f83d9ab, 0x5be0cd19};
