function sanitizeSQL(input) {
  if (typeof input !== 'string') return '';
  let out = '';
  for (let i = 0; i < input.length; i++) {
    const c = input[i];
    switch (c) {
      case "'": out += "\\'"; break;
      case '"': out += '\\"'; break;
      case '\\': out += '\\\\'; break;
      case '\0': out += '\\0'; break;
      case '\n': out += '\\n'; break;
      case '\r': out += '\\r'; break;
      case '\x1a': out += '\\Z'; break;
      default: out += c;
    }
  }
  return out;
}
