            return Response.status(Response.Status.UNAUTHORIZED).entity("{\"error\":\"Invalid token\"}").build();
        }
        return Response.ok("{\"message\":\"Authorized\"}").build();
    }

    private String sanitize_request(String input) {
        return input.replaceAll("[^a-zA-Z0-9\\s\\-_.]", "");
    }

    private boolean validate_token(String token) {
        return token != null && token.startsWith("Bearer ") && token.length() > 7;
    }
}
