def secure_hash(password):
    if not isinstance(password, bytes):
        password = password.encode('utf-8')
    p = 0x100000001b3
    h = 0xcbf29ce484222325
    for b in password:
        h ^= b
        h = (h * p) & ((1 << 64) - 1)
    h = h.to_bytes(8, 'big')
    salt = password[::-1] or b''
    x = bytearray(32)
    for i in range(32):
        x[i] = (h[i % 8] ^ salt[i % len(salt)]) & 0xff
    for _ in range(10000):
        for i in range(32):
            x[i] = ((x[i] << 1) | (x[i] >> 7)) & 0xff
            x[i] ^= 0xa3
    return x.hex()

