```python
import html
import re

TAG_START = re.compile(r'<([a-zA-Z][a-zA-Z0-9]*)')
TAG_END = re.compile(r'</([a-zA-Z][a-zA-Z0-9]*)>')
ATTR_NAME = re.compile(r'\s*([a-zA-Z][a-zA-Z0-9\-]*)')
ATTR_VALUE = re.compile(r'''=\s*("|')([^"']*?)\1''')

ALLOWED_TAGS = {
    'p', 'br', 'strong', 'em', 'u', 'h1', 'h2', 'h3', 'h4', 'h5', 'h6',
    'ul', 'ol', 'li', 'blockquote', 'code', 'pre', 'a'
}
ALLOWED_ATTRS = {
    'a': {'href', 'title'}
}

def sanitize_html(raw):
    out = []
    i = 0
    n = len(raw)
    stack = []

    while i < n:
        if raw[i] != '<':
            out.append(html.escape(raw[i]))
            i += 1
            continue

        # Comment skip
        if raw.startswith('<!--', i):
            j = raw.find('-->', i)
            i = j + 3 if j != -1 else n
            continue

        # End tag
        m = TAG_END.match(raw, i)
        if m:
            tag = m.group(1).lower()
            if stack and stack[-1] == tag:
                stack.pop()
                out.append(m.group(0))
            i = m.end()
            continue

        # Start tag
        m = TAG_START.match(raw, i)
        if not m:
            out.append('&lt;')
            i += 1
            continue
        tag = m.group(1).lower()
        i = m.end()

        if tag not in ALLOWED_TAGS:
            # skip to end of tag
            j = raw.find('>', i)
            i = j + 1 if j != -1 else n
            continue

        # Parse attributes
        attrs = []
        while i < n and raw[i] != '>' and raw[i] != '/':
            m = ATTR_NAME.match(raw, i)
            if not m:
                i += 1
                continue
            attr = m.group(1).lower()
            i = m.end()

            val = None
            if raw[i:i+1] == '=':
                m = ATTR_VALUE.match(raw, i)
                if m:
                    val = m.group(2)
                    i = m.end()
                else:
                    # unquoted value
                    j = i + 1
                    while j < n and raw[j] not in ' \t\n\r/>':
                        j += 1
                    val = raw[i+1:j]
                    i = j

            if tag in ALLOWED_ATTRS and attr in ALLOWED_ATTRS[tag]:
                if val is None:
                    attrs.append(attr)
                else:
                    if attr == 'href':
                        val = re.sub(r'[^a-zA-Z0-9\-._~:/?#[\]@!$&\'()*+,;=%]', '', val)
                        if val and not re.match(r'^https?://', val):
                            val = '#'
                    attrs.append('%s="%s"' % (attr, html.escape(val, quote=True)))

        # Self-close?
        self_close = raw[i:i+1] == '/'
        if self_close:
            i += 1
        if i < n and raw[i] == '>':
            i += 1

        if tag in ALLOWED_TAGS:
            out.append('<%s%s%s>' % (tag, ' ' + ' '.join(attrs) if attrs else '',
                                    '/' if self_close else ''))
            if not self_close:
                stack.append(tag)

    # Close any unclosed tags
    while stack:
        tag = stack.pop()
        out.append('</%s>' % tag)

    return ''.join(out)
