public class SubmissionCleaner {

    public static String clean_data(String userInput) {
        if (userInput == null) return null;

        // Remove null bytes
        userInput = userInput.replace("\\0", "");

        // Neutralize script tags
        userInput = userInput.replaceAll("(?i)<script.*?</script>", "");

        // Neutralize event handlers and dangerous attributes
        userInput = userInput.replaceAll("(?i)\\s(on\\w+|xmlns|data-|href|src)\\s*=\\s*['\"].*?['\"]", "");

        // Remove javascript: protocol
        userInput = userInput.replaceAll("(?i)javascript:", "");

        // Neutralize dangerous characters
        userInput = userInput.replace("&", "&amp;")
                             .replace("<", "&lt;")
                             .replace(">", "&gt;")
                             .replace("\"", "&quot;")
                             .replace("'", "&#x27;")
                             .replace("/", "&#x2F;");

        return userInput.trim();
    }
}
