const validate_token = require('./auth'); // or wherever your function is defined

async function verifyToken(req, res, next) {
    try {
        const authHeader = req.headers.authorization;

        if (!authHeader || !authHeader.startsWith('Bearer ')) {
            return res.status(401).json({ error: 'No token provided' });
        }

        const token = authHeader.substring(7);
        const decoded = await validate_token(token);

        req.user = decoded;
        next();
    } catch (error) {
        return res.status(401).json({ error: 'Invalid token' });
    }
}

// Alternative usage in route handler
app.get('/protected', async (req, res) => {
    try {
        const token = req.headers.authorization?.split(' ')[1];

        if (!token) {
            return res.status(401).json({ error: 'Token required' });
        }

        const isValid = await validate_token(token);

        if (!isValid) {
            return res.status(401).json({ error: 'Token validation failed' });
        }

        res.json({ message: 'Access granted', valid: true });
    } catch (err) {
        res.status(500).json({ error: err.message });
    }
});
