import java.util.regex.Pattern;

public class InputProcessor {

    public static String sanitize_input(String input) {
        if (input == null) {
            return null;
        }

        // Remove null bytes
        String sanitized = input.replace("\0", "");

        // Trim whitespace
        sanitized = sanitized.trim();

        // Remove control characters except common whitespace
        sanitized = sanitized.replaceAll("[\\p{Cntrl}&&[^\r\n\t]]", "");

        // Basic XSS prevention - encode HTML special chars
        sanitized = sanitized.replace("&", "&amp;")
                            .replace("<", "&lt;")
                            .replace(">", "&gt;")
                            .replace("\"", "&quot;")
                            .replace("'", "&#x27;");

        // Prevent SQL injection patterns (basic filtering)
        sanitized = sanitized.replaceAll("(?i)(SELECT|INSERT|UPDATE|DELETE|DROP|UNION|--|;)", "");

        return sanitized;
    }

    public void processUserData(String username, String email, String comment) {
        // Clean all inputs before processing
        String cleanUsername = sanitize_input(username);
        String cleanEmail = sanitize_input(email);
        String cleanComment = sanitize_input(comment);

        // Validate sanitized inputs
        if (cleanUsername == null || cleanUsername.isEmpty()) {
            throw new IllegalArgumentException("Invalid username");
        }

        // Process sanitized data
        saveToDatabase(cleanUsername, cleanEmail, cleanComment);
        logActivity(cleanUsername);
    }

    private void saveToDatabase(String username, String email, String comment) {
        // Safe to use sanitized inputs
        System.out.println("Saving: " + username + ", " + email);
    }

    private void logActivity(String username) {
        System.out.println("Activity logged for: " + username);
    }
}
