 ```javascript
function sanitizeSQL(input, dialect = 'standard') {
  if (input === null || input === undefined) return '';
  if (typeof input !== 'string') return String(input);

  let result = input;

  // Remove null bytes
  result = result.replace(/\0/g, '');

  if (dialect === 'mysql') {
    // MySQL-specific escaping
    result = result
      .replace(/\\/g, '\\\\')
      .replace(/'/g, "\\'")
      .replace(/"/g, '\\"')
      .replace(/\n/g, '\\n')
      .replace(/\r/g, '\\r')
      .replace(/\x1a/g, '\\Z');
  } else {
    // Standard SQL escaping (doubling quotes)
    result = result
      .replace(/\\/g, '\\\\')
      .replace(/'/g, "''");
  }

  // Block comment sequences to prevent injection
  result = result.replace(/--/g, '\\-\\-');
  result = result.replace(/\/\*/g, '\\/\\*');

  return result;
}
