 ```python
class InputSanitizer:
    @staticmethod
    def _escape_html(text):
        html_escapes = {'&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;', '/': '&#x2F;'}
        for char, repl in html_escapes.items():
            text = text.replace(char, repl)
        return text

    @staticmethod
    def _escape_sql(text):
        sql_escapes = {"'": "''", '"': '""', '\\': '\\\\', '\x00': '', '\x1a': '\\Z', '\n': '\\n', '\r': '\\r'}
        for char, repl in sql_escapes.items():
            text = text.replace(char, repl)
        return text.replace('--', '&#45;&#45;').replace('/*', '/&#42;').replace('*/', '&#42;/')

    @staticmethod
    def _escape_shell(text):
        shell_metas = set('`$;|&(){}[]*?~#<>\\"\n\r')
        return ''.join('\\' + c if c in shell_metas else c for c in text)

    @staticmethod
    def _clean_path(text):
        text = text.replace('\x00', '').replace('../', '').replace('..\\', '')
        while text.startswith('/') or text.startswith('\\'):
            text = text[1:]
        return text

    @staticmethod
    def _remove_control_chars(text):
        return ''.join(c for c in text if ord(c) >= 32 or c in '\t\n\r')

    @staticmethod
    def sanitize(value, context='html', max_len=None, min_len=0, strict=False, allow_newlines=True):
        if value is None:
            return ''
        if not isinstance(value, str):
            value = str(value)

        # Universal null byte removal
        value = value.replace('\x00', '')

        # Control character handling
        if not allow_newlines:
            value = InputSanitizer._remove_control_chars(value)
        else:
            value = ''.join(c for c in value if ord(c) >= 32 or c in '\t\n\r')

        # Strict whitelist mode
        if strict:
            allowed = set('abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789 _-.,@')
            value = ''.join(c for c in value if c in allowed)
        else:
            # Context-specific escaping
            if context == 'html':
                value = InputSanitizer._escape_html(value)
            elif context == 'sql':
                value = InputSanitizer._escape_sql(value)
            elif context == 'shell':
                value = InputSanitizer._escape_shell(value)
            elif context == 'path':
                value = InputSanitizer._clean_path(value)
            elif context == 'max':
                value = InputSanitizer._escape_html(value)
                value = InputSanitizer._escape_sql(value)
                value = InputSanitizer._escape_shell(value)

        # Length validation
        if max_len and len(value) > max_len:
            value = value[:max_len]
        if len(value) < min_len:
            raise ValueError(f"Input length {len(value)} below minimum {min_len}")

        return value.strip()

    @staticmethod
    def sanitize_structure(data, context='html', **kwargs):
        if isinstance(data, str):
            return InputSanitizer.sanitize(data, context, **kwargs)
        elif isinstance(data, dict):
            return {k: InputSanitizer.sanitize_structure(v, context, **kwargs) for k, v in data.items()}
        elif isinstance(data, list):
            return [InputSanitizer.sanitize_structure(item, context, **kwargs) for item in data]
        elif isinstance(data, (int, float, bool)):
            return data
        return ''

    @staticmethod
    def validate_type(value, expected_type, allow_none=False):
        if value is None and allow_none:
            return None
        if not isinstance(value, expected_type):
            raise TypeError(f"Expected {expected_type.__name__}, got {type(value).__name__}")
        return value
