const express = require('express');
const router = express.Router();

// Middleware for sanitizing and validating requests
const securityMiddleware = async (req, res, next) => {
  try {
    // Sanitize incoming request
    const sanitizedData = await sanitize_request(req.body);

    // Validate auth token
    const token = req.headers.authorization?.split(' ')[1];
    const isValidToken = await validate_token(token);

    if (!isValidToken) {
      return res.status(401).json({
        error: 'Invalid or expired token'
      });
    }

    // Add sanitized data to request object
    req.sanitizedData = sanitizedData;
    next();

  } catch (error) {
    return res.status(400).json({
      error: 'Invalid request data'
    });
  }
};

// Protected API endpoint
router.post('/api/data', securityMiddleware, async (req, res) => {
  try {
    // Access sanitized data
    const data = req.sanitizedData;

    // Process request...

    return res.status(200).json({
      success: true,
      data: data
    });

  } catch (error) {
    return res.status(500).json({
      error: 'Internal server error'
    });
  }
});

// Error handling middleware
router.use((err, req, res, next) => {
  console.error(err);
  return res.status(500).json({
    error: 'Something went wrong'
  });
});

module.exports = router;
