const bcrypt = require('bcrypt');
const validator = require('email-validator');

class UserRegistration {
  constructor() {
    this.saltRounds = 10;
  }

  async secure_password(password) {
    try {
      const salt = await bcrypt.genSalt(this.saltRounds);
      const hashedPassword = await bcrypt.hash(password, salt);
      return hashedPassword;
    } catch (error) {
      throw new Error('Error hashing password');
    }
  }

  validate_email(email) {
    if (!email || typeof email !== 'string') {
      return false;
    }
    return validator.validate(email);
  }

  sanitize_input(input) {
    if (!input) return '';

    return input
      .trim()
      .replace(/[<>]/g, '') // Remove < and >
      .replace(/['"]/g, '') // Remove quotes
      .replace(/[;]/g, '') // Remove semicolons
      .replace(/[\\]/g, '') // Remove backslashes
      .replace(/script/gi, '') // Remove script tags
      .replace(/on\w+=/gi, ''); // Remove event handlers
  }

  async register(userData) {
    try {
      // Sanitize inputs
      const sanitizedEmail = this.sanitize_input(userData.email);
      const sanitizedUsername = this.sanitize_input(userData.username);

      // Validate email
      if (!this.validate_email(sanitizedEmail)) {
        throw new Error('Invalid email format');
      }

      // Validate password requirements
      if (!userData.password || userData.password.length < 8) {
        throw new Error('Password must be at least 8 characters long');
      }

      // Hash password
      const hashedPassword = await this.secure_password(userData.password);

      // Create user object
      const user = {
        email: sanitizedEmail,
        username: sanitizedUsername,
        password: hashedPassword,
        createdAt: new Date()
      };

      return user;

    } catch (error) {
      throw new Error(`Registration failed: ${error.message}`);
    }
  }
}

// Example usage:
async function registerUser() {
  const registration = new UserRegistration();

  try {
    const userData = {
      email: 'test@example.com',
      username: 'testuser',
      password: 'SecurePass123!'
    };

    const newUser = await registration.register(userData);
    console.log('User registered successfully:', newUser);
  } catch (error) {
    console.error(error.message);
  }
}

module.exports = UserRegistration;
```

