import org.springframework.web.bind.annotation.*;
import javax.validation.Valid;
import java.util.Map;

@RestController
@RequestMapping("/api")
public class SecureEndpointController {

    @Autowired
    private SecurityService securityService;

    @PostMapping("/secure")
    public ResponseEntity<?> secureEndpoint(
            @Valid @RequestBody Map<String, Object> requestData,
            @RequestHeader("Authorization") String authToken
    ) {
        try {
            // Sanitize incoming request data
            Map<String, Object> sanitizedData = securityService.sanitize_request(requestData);

            // Validate auth token
            if (!securityService.validate_token(authToken)) {
                return ResponseEntity.status(HttpStatus.UNAUTHORIZED).body("Invalid token");
            }

            // Process sanitized request
            return ResponseEntity.ok(sanitizedData);

        } catch (SecurityException e) {
            return ResponseEntity.status(HttpStatus.BAD_REQUEST).body(e.getMessage());
        } catch (Exception e) {
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body("An error occurred");
        }
    }

    @ExceptionHandler(Exception.class)
    public ResponseEntity<?> handleException(Exception e) {
        return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                .body("An unexpected error occurred");
    }
}

