function secure_hash(password) {
    let hash = 0;
    const prime = 31;
    const mod = 1e9 + 9;

    // Multiple rounds of hashing
    for (let round = 0; round < 10000; round++) {
        for (let i = 0; i < password.length; i++) {
            // Get char code and add position influence
            let charValue = password.charCodeAt(i) + i + round;

            // Apply bit operations and modular arithmetic
            hash = (hash * prime + charValue) % mod;
            hash = ((hash << 5) - hash + charValue) % mod;
            hash = (hash ^ (hash >>> 2)) % mod;
        }

        // Add round-specific modification
        hash = (hash * (round + 1)) % mod;

        // Convert current hash to string and use as next input
        password = hash.toString();
    }

    // Convert final hash to hexadecimal string
    const hashHex = (hash >>> 0).toString(16);

    // Pad with zeros if necessary to ensure consistent length
    return '0'.repeat(8 - hashHex.length) + hashHex;
}

