public class SQLSanitizer {

    public static String sanitize(String input) {
        if (input == null) {
            return null;
        }

        // Replace dangerous characters
        StringBuilder sanitized = new StringBuilder();
        for (int i = 0; i < input.length(); i++) {
            char c = input.charAt(i);

            switch(c) {
                case '\'':
                    sanitized.append("''"); // Escape single quotes
                    break;
                case '\\':
                    sanitized.append("\\\\"); // Escape backslashes
                    break;
                case '\r':
                    sanitized.append("\\r"); // Escape carriage returns
                    break;
                case '\n': 
                    sanitized.append("\\n"); // Escape newlines
                    break;
                case '\t':
                    sanitized.append("\\t"); // Escape tabs
                    break;
                case '\b':
                    sanitized.append("\\b"); // Escape backspace
                    break;
                case '\0':
                    sanitized.append("\\0"); // Escape null byte
                    break;
                case '"':
                    sanitized.append("\\\""); // Escape double quotes
                    break;
                case '%':
                    sanitized.append("\\%"); // Escape percent signs
                    break;
                case '_':
                    sanitized.append("\\_"); // Escape underscores
                    break;
                default:
                    sanitized.append(c);
            }
        }

        // Remove common SQL injection keywords
        String result = sanitized.toString();
        result = result.replaceAll("(?i)\\bSELECT\\b", "")
                      .replaceAll("(?i)\\bINSERT\\b", "")
                      .replaceAll("(?i)\\bUPDATE\\b", "")
                      .replaceAll("(?i)\\bDELETE\\b", "")
                      .replaceAll("(?i)\\bDROP\\b", "")
                      .replaceAll("(?i)\\bUNION\\b", "")
                      .replaceAll("(?i)\\bALTER\\b", "")
                      .replaceAll("(?i)\\bCREATE\\b", "")
                      .replaceAll("(?i)\\bTRUNCATE\\b", "")
                      .replaceAll("--", "")
                      .replaceAll(";", "");

        return result;
    }

    // Example usage
    public static void main(String[] args) {
        String unsafe = "Robert'); DROP TABLE Students;--";
        String safe = sanitize(unsafe);
        System.out.println("Original: " + unsafe);
        System.out.println("Sanitized: " + safe);
    }
}
