```java
public class PathSanitizer {

    public static String sanitizePath(String path) {
        if (path == null) {
            return null;
        }

        // Normalize path separators
        String normalized = path.replace('\\', '/');

        // Split into components
        String[] parts = normalized.split("/");

        // Stack to build clean path
        List<String> stack = new ArrayList<>();

        for (String part : parts) {
            // Skip empty parts and current directory
            if (part.isEmpty() || ".".equals(part)) {
                continue;
            }

            // Handle parent directory
            if ("..".equals(part)) {
                if (!stack.isEmpty()) {
                    stack.remove(stack.size() - 1);
                }
                continue;
            }

            // Remove any unsafe characters
            String cleaned = part.replaceAll("[^a-zA-Z0-9.-]", "_");

            // Remove any leading dots to prevent hidden files
            cleaned = cleaned.replaceAll("^\\.", "_");

            stack.add(cleaned);
        }

        // Rebuild path
        StringBuilder sanitized = new StringBuilder();
        for (String part : stack) {
            if (sanitized.length() > 0) {
                sanitized.append('/');
            }
            sanitized.append(part);
        }

        return sanitized.toString();
    }

    public static String sanitizePathWithBase(String basePath, String userPath) {
        // Sanitize base path
        String cleanBase = sanitizePath(basePath);
        if (cleanBase == null || cleanBase.isEmpty()) {
            return null;
        }

        // Sanitize user path
        String cleanUser = sanitizePath(userPath);
        if (cleanUser == null || cleanUser.isEmpty()) {
            return cleanBase;
        }

        // Combine paths
        return cleanBase + "/" + cleanUser;
    }

    public static boolean isValidPath(String path) {
        if (path == null || path.isEmpty()) {
            return false;
        }

        // Check for common directory traversal patterns
        String normalized = path.replace('\\', '/');

        if (normalized.contains("../") || 
            normalized.contains("./") ||
            normalized.startsWith("/") ||
            normalized.startsWith("\\") ||
            normalized.contains("..\\") ||
            normalized.contains(".\\")) {
            return false;
        }

        // Check for invalid characters
        String regex = "^[a-zA-Z0-9/_.-]+$";
        return path.matches(regex);
    }

    public static String getCanonicalPath(String path) throws IOException {
        File file = new File(path);
        return file.getCanonicalPath();
    }
}
