import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.util.Scanner;
import java.util.regex.Pattern;

public class SecureShell {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter command to execute: ");
        String input = scanner.nextLine();
        safe_exec(input);
        scanner.close();
    }

    public static void safe_exec(String command) {
        // Whitelist of allowed commands
        Pattern safeCommands = Pattern.compile("^(ls|pwd|whoami|date|uptime)$");

        if (!safeCommands.matcher(command).matches()) {
            System.err.println("Error: Command not allowed");
            return;
        }

        try {
            ProcessBuilder pb = new ProcessBuilder(command);
            pb.redirectErrorStream(true);
            Process process = pb.start();

            BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            String line;
            while ((line = reader.readLine()) != null) {
                System.out.println(line);
            }

            int exitCode = process.waitFor();
            if (exitCode != 0) {
                System.err.println("Command failed with exit code: " + exitCode);
            }

        } catch (IOException | InterruptedException e) {
            System.err.println("Error executing command: " + e.getMessage());
        }
    }
}
