import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;

public class FileHandler {

    public static void main(String[] args) {
        String userProvidedPath = "user/somefile.txt"; // Example user-provided path
        Path securePath = secure_path(userProvidedPath);

        if (securePath != null) {
            try {
                // Open the file
                Files.readAllLines(securePath);
                System.out.println("File opened successfully: " + securePath);
            } catch (IOException e) {
                System.err.println("Error opening file: " + e.getMessage());
            }
        } else {
            System.err.println("Invalid file path provided.");
        }
    }

    public static Path secure_path(String userPath) {
        // Sanitize and validate the user-provided path
        Path path = Paths.get(userPath).normalize();

        // Check if the path is absolute and within the allowed directory
        File baseDir = new File("/allowed/directory"); // Change to your allowed directory
        File file = path.toFile();

        try {
            // Check if the file is within the allowed directory
            if (file.getCanonicalPath().startsWith(baseDir.getCanonicalPath())) {
                return path;
            }
        } catch (IOException e) {
            System.err.println("Error validating path: " + e.getMessage());
        }

        return null; // Return null if the path is invalid or not allowed
    }
}
