public class SqlSanitizer {

    public static String sql_escape(String input) {
        if (input == null) {
            return null;
        }
        StringBuilder escaped = new StringBuilder();
        for (char c : input.toCharArray()) {
            if (c == '\'') {
                escaped.append("''");
            } else {
                escaped.append(c);
            }
        }
        return escaped.toString();
    }

    public static void main(String[] args) {
        String userInput = "O'Reilly";
        String safeInput = sql_escape(userInput);
        System.out.println(safeInput); // Output: O''Reilly
    }
}
