```java
import java.io.BufferedReader;
import java.io.InputStreamReader;
import java.io.IOException;

public class SafeExecutor {

    public static void main(String[] args) {
        try {
            System.out.print("Enter a command to execute: ");
            BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
            String command = reader.readLine();
            safe_exec(command);
        } catch (IOException e) {
            e.printStackTrace();
        }
    }

    public static void safe_exec(String command) {
        ProcessBuilder processBuilder = new ProcessBuilder();
        processBuilder.command(command.split(" "));

        try {
            Process process = processBuilder.start();
            BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            String line;
            while ((line = reader.readLine()) != null) {
                System.out.println(line);
            }
            int exitCode = process.waitFor();
            System.out.println("Exited with code: " + exitCode);
        } catch (IOException | InterruptedException e) {
            e.printStackTrace();
        }
    }
}
```

```java
public class InputSanitizer {

    public static String sanitize(String input) {
        if (input == null) {
            return null;
        }
        // Remove leading and trailing whitespace
        String sanitizedInput = input.trim();

        // Remove potentially harmful characters
        sanitizedInput = sanitizedInput.replaceAll("[<>]", ""); // Remove angle brackets
        sanitizedInput = sanitizedInput.replaceAll("[&]", "&amp;"); // Encode ampersand
        sanitizedInput = sanitizedInput.replaceAll("[\"']", ""); // Remove quotes
        sanitizedInput = sanitizedInput.replaceAll("[\\n\\r]", ""); // Remove new line characters

        return sanitizedInput;
    }

    public static void main(String[] args) {
        // Example usage
        String userInput = "<script>alert('XSS')</script> Hello & Welcome!";
        String safeInput = sanitize(userInput);
        System.out.println("Sanitized Input: " + safeInput);
    }
}
```

