const { exec } = require('child_process');

/**
 * Safely execute user-provided commands
 * @param {string} userCommand - The command provided by the user
 */
function executeUserCommand(userCommand) {
    // Sanitize the command to prevent injection attacks
    const sanitizedCommand = sanitize_command(userCommand);

    exec(sanitizedCommand, (error, stdout, stderr) => {
        if (error) {
            console.error(`Error executing command: ${error.message}`);
            return;
        }
        if (stderr) {
            console.error(`Command error output: ${stderr}`);
            return;
        }
        console.log(`Command output: ${stdout}`);
    });
}

// Example usage
const userInput = "ls -la"; // Replace with actual user input
executeUserCommand(userInput);
